def _parse_ifd(tiff: bytes, endian: str, ifd_offset: int) -> dict[int, object]:
    if ifd_offset + 2 > len(tiff):
        return {}
    entry_count = struct.unpack_from(endian + "H", tiff, ifd_offset)[0]
    entries: dict[int, object] = {}
    cursor = ifd_offset + 2
    for _ in range(entry_count):
        if cursor + 12 > len(tiff):
            break
        tag, type_id, count, value_field = struct.unpack_from(endian + "HHII", tiff, cursor)
        cursor += 12
        value = _read_value(tiff, endian, type_id, count, value_field)
        if value is not None:
            entries[tag] = value
    return entries

