def _normalize_tag_value(tag: int, value: object) -> object:
    if tag in {TAG_ORIENTATION, TAG_PIXEL_X, TAG_PIXEL_Y}:
        if isinstance(value, list):
            return value[0]
        return value
    if tag in {TAG_MAKE, TAG_MODEL, TAG_SOFTWARE, TAG_DATE_TIME, TAG_DATE_TIME_ORIGINAL, TAG_DATE_TIME_DIGITIZED}:
        return str(value)
    if tag in {TAG_GPS_LATITUDE, TAG_GPS_LONGITUDE}:
        return value
    return value

